INSERT INTO public.site_translations (lang, data) VALUES ('ro', '{"ddos":{"hero":{"badge":"Protecție DDoS pentru companii","titleStart":"Oprește atacurile.","titleHighlight":"Rămâi online.","subtitle":"Protecție DDoS puternică ce menține serviciile tale funcționale. Atenuare permanentă cu zero încetiniri și alerte de amenințări în timp real.","ctaProtected":"Obține protecție","ctaEngineer":"Discută cu un inginer","badgeCapacity":"Capacitate 400+ Gbps","badgeSoc":"SOC 24/7","badgeMitigation":"Atenuare <10s"},"howItWorks":{"title":"Cum funcționează","subtitle":"Procesul nostru în 5 pași oprește atacurile L3/L4/L7 înainte ca acestea să ajungă la tine.","step1Title":"Detecție","step1Desc":"Analizăm traficul tău în timp real pentru a detecta amenințările instantaneu.","step2Title":"Clasificare","step2Desc":"Tipurile de atac sunt identificate și sortate în câteva milisecunde.","step3Title":"Curățare","step3Desc":"Traficul rău este filtrat la marginea rețelei înainte de a ajunge la serverul tău.","step4Title":"Conductă curată","step4Desc":"Doar traficul legitim ajunge la infrastructura ta.","step5Title":"Raportare","step5Desc":"Obține analize complete ale atacurilor și informații în timp real."},"tabs":{"title":"Protecție multi-strat","subtitle":"Apărare cuprinzătoare pe toți vectorii de atac cu protecție specializată la fiecare strat.","features":"Caracteristici","attacksBlocked":"Atacuri blocate","bestFor":"Cel mai bun pentru","labels":{"l3l4":"L3/L4","l7":"L7","bot":"Atenuare bot","waf":"WAF/Reguli","rate":"Limitare rată"},"bestForText":{"l3l4":"Infrastructură de rețea și servere de jocuri","l7":"Aplicații web și API-uri","bot":"Comerț electronic și pagini de autentificare","waf":"Aplicații sensibile și conformitate","rate":"API-uri și puncte finale de autentificare"}},"monitoring":{"title":"Tablou de bord live pentru atacuri","subtitle":"Vizibilitate în timp real asupra amenințărilor și stării de atenuare în întreaga infrastructură protejată.","allProtected":"Toate sistemele protejate","lastUpdated":"Ultima actualizare: Chiar acum","attacksMitigated":"Atacuri atenuate","fromLastWeek":"+23% față de săptămâna trecută","peakBandwidth":"Lățime de bandă maximă","largestToday":"Cel mai mare atac astăzi","avgMitigation":"Atenuare medie","timeToMitigate":"Timp de atenuare","activePops":"POP-uri active","scrubbingCenters":"Centre de curățare","topVectors":"Vectori de atac principali","trafficLast24":"Trafic (ultimele 24h)","totalClean":"Total curat","totalBlocked":"Total blocat","uptime":"Timp de funcționare","attackOrigins":"Origini atacuri"},"useCases":{"title":"Protecție pentru fiecare caz de utilizare","subtitle":"De la servere de jocuri la infrastructură enterprise, te acoperim.","pain":"Problemă","solution":"Soluție","outcome":"Rezultat","items":{"games":{"title":"Servere de jocuri","pain":"Jucătorii experimentează lag și deconectări în timpul atacurilor","solution":"Atenuarea sub 10ms menține jocul fluid","outcome":"Zero întreruperi, jucători fericiți"},"web":{"title":"Aplicații web","pain":"Site-urile devin indisponibile în timpul inundațiilor HTTP","solution":"Protecția L7 filtrează cererile malițioase","outcome":"Timp de funcționare și performanță consistente"},"api":{"title":"API-uri","pain":"Limitat de atacatori, nu de design","solution":"Limitare inteligentă a ratei și detectare a roboților","outcome":"API-urile rămân receptive pentru utilizatorii reali"},"voip":{"title":"Servicii VoIP","pain":"Calitatea apelurilor se degradează sub inundațiile SIP","solution":"Atenuare conștientă de protocol pentru traficul VoIP","outcome":"Apeluri clare, fără întreruperi"},"vpn":{"title":"VPN corporativ","pain":"Lucrătorii la distanță nu se pot conecta în timpul atacurilor","solution":"Protecție permanentă pentru punctele finale VPN","outcome":"Acces la distanță sigur și fiabil"},"ecommerce":{"title":"Comerț electronic","pain":"Venituri pierdute în timpul atacurilor la checkout","solution":"Atenuarea roboților protejează tranzacțiile","outcome":"Cumpărături sigure, venituri maximizate"}}},"faq":{"title":"Întrebări frecvente","subtitle":"Tot ce trebuie să știi despre serviciile noastre de protecție DDoS.","items":[{"q":"Care este diferența dintre protecția DDoS L3/L4 și L7?","a":"Protecția L3/L4 gestionează atacurile volumetrice care vizează straturile de rețea și transport. Protecția L7 se concentrează pe atacurile la nivel de aplicație. Pentru o acoperire completă, recomandăm ambele."},{"q":"Suportați protecția DDoS specifică jocurilor?","a":"Da! Protecția noastră este optimizată pentru titluri populare, inclusiv Minecraft, FiveM, Rust, ARK și altele."},{"q":"Atenuarea DDoS va adăuga latență traficului meu?","a":"Atenuarea noastră permanentă adaugă mai puțin de 1ms de latență în condiții normale."},{"q":"Cum îmi integrez infrastructura?","a":"Integrarea este simplă: 1) Înregistrează-te. 2) Actualizează DNS-ul sau BGP. 3) Activăm protecția în câteva minute."},{"q":"Trebuie să-mi schimb înregistrările DNS?","a":"Pentru majoritatea configurărilor, da. Pentru implementări mari, suportăm rutarea BGP."},{"q":"Ce rapoarte primesc?","a":"Tablouri de bord în timp real cu modele de trafic, vectori de atac și amenințări blocate."},{"q":"Pot proteja mai multe IP-uri?","a":"Da. Standard 1 IP, Advanced 5 IP-uri, Enterprise nelimitat."},{"q":"Ce se întâmplă în timpul unui atac mare?","a":"Rețeaua noastră se scalează automat până la 500+ Gbps."},{"q":"Există garanție de returnare a banilor?","a":"Da, 30 de zile pentru toate planurile."},{"q":"Cât de repede pot începe?","a":"Protecția poate fi activă în câteva minute de la înregistrare."}]},"finalCta":{"title":"Ești gata să oprești întreruperile?","subtitle":"Mii de companii au încredere în Hoxta. Obține protecție în câteva minute.","ctaStart":"Începe acum","ctaQuote":"Cere o ofertă","moneyBack":"Garanție 30 de zile","instantActivation":"Activare instantanee","expertSupport":"Suport expert 24/7"}}}'::jsonb)
ON CONFLICT (lang) DO UPDATE SET data = public.jsonb_deep_merge(public.site_translations.data, EXCLUDED.data), updated_at = now();